VALUES
  ('judicial-57112235-moex-00597', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依行刑累進處遇條例第19條責任分數之規定，下列敘述何者錯誤？', '["各級受刑人之責任分數，以其所得成績分數抵銷之", "少年受刑人之責任分數，按一般受刑人責任分數標準減少二分之一計算", "累犯受刑人之責任分數，按一般受刑人責任分數標準逐級增加其責任分數三分之一", "撤銷假釋受刑人責任分數，按一般受刑人責任分數標準逐級增加責任分數二分之一"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00598', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '作業收入扣除作業支出後稱作業賸餘，其分配之方式，下列敘述何者錯誤？', '["提百分之六十充勞作金", "提百分之十充犯罪被害人補償費用", "提百分之十充受刑人飲食補助費用", "提百分之二十充獎勵費用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00599', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '特定受刑人釋放前，應通知家屬或受刑人認為適當之人來監接回。依監獄行刑法規定，下列敘述何者 正確？', '["衰老、重病、身心障礙不能自理生活之受刑人", "家住離島、偏遠地區交通不方便之受刑人", "外國籍、無國籍之受刑人", "出監前發生重大違反紀律事件之受刑人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00600', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法第7條，有關監獄為保障受刑人權益，下列敘述何者正確？', '["監獄應設立內部及外部視察小組，監督保障受刑人之權益", "監獄應設立獨立之外部視察小組，置委員3人至7人，任期2年，均為無給職，由監督機關陳報法 務部核定後遴聘之", "視察小組委員中，任一性別委員不得少於2分之1", "視察小組應就監獄運作及受刑人權益相關事項進行視察，並每半年提出報告，陳報監督機關備查"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00601', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人入監行健康檢查，有關應拒絕收監之規定，下列敘述何者錯誤？', '["有客觀事實足認其身心狀況欠缺辨識能力，致不能處理自己事務", "現罹患疾病，因執行而不能保其生命", "懷胎3月以上，或生產未滿3月", "罹患法定傳染病，因執行有引起群聚感染之虞"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00602', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄受刑人之移監規定，下列敘述何者錯誤？', '["監獄受刑人有嚴重超額時，監獄可視實際收容狀況，必要時做機動性調整移監", "受刑人有特殊且必要之處遇需求，而本監無法提供相應之資源，監獄得報請監督機關核准移送指定之 監獄", "監獄依據受刑人調查分類之結果，認須加強教化，得報請監督機關核准移送指定之監獄", "受刑人對於其他受刑人有顯著之不良影響，有離開本監之必要，得報請監督機關核准移送指定之監獄"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00603', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄對受刑人之給養，下列敘述何者錯誤？', '["為維護受刑人之身體健康，監獄應供給飲食，並提供必要之衣類、寢具、物品及其他器具", "受刑人得因宗教信仰或其他因素，請求監獄提供適當之飲食", "受刑人攜子入監，子女之食物、衣類、及必需用品，均由監獄提供之", "受刑人禁用酒類、檳榔。監獄得許受刑人於指定之時間、處所吸菸"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00604', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄受刑人醫療健保之規定，下列敘述何者錯誤？', '["受刑人為全民健康保險之保險對象", "受刑人如無全民健康保險憑證者，得由監獄逕行代為申請", "受刑人經暫行停止保險給付者，其罹患疾病時之醫療費用，由監獄及受刑人分攤", "受刑人換發、補發、代為申請全民健康保險憑證衍生之費用，監獄得由受刑人保管金或勞作金中扣除"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00605', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄對受刑人有妨害監獄秩序或安全行為時，得施以懲罰之規定，下列敘述何者錯誤？', '["警告", "停止接受送入飲食3日至7日", "停止使用自費購買之非日常生活必需品7日至14日", "移入違規舍5日至90日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00606', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關受刑人入監檢查，下列敘述何者錯誤？', '["受刑人入監時，應檢查其身體、衣類及攜帶之物品，一律採集其尿液檢驗", "檢查受刑人身體，如須脫衣檢查時，應於有遮蔽之處所為之，並注意維護受刑人隱私及尊嚴", "非有事實足認受刑人有夾藏違禁物品或其他危害監獄秩序及安全之虞，不得為侵入性檢查", "如須為侵入性檢查，應經監獄長官核准，並由醫事人員為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
